1	import { useCallback, useEffect, useRef, useState } from 'react';
2	import {
3	  Keyboard,
4	  Platform,
5	  StyleSheet,
6	  Text,
7	  TextInput,
8	  TouchableWithoutFeedback,
9	  View,
10	} from 'react-native';
11	import { BottomSheet } from '@/components/primitives/BottomSheet';
12	import { ButtonPrimary } from '@/components/primitives/Button';
13	import { useToast } from '@/components/primitives/Toast';
14	import { colors, radii, shadows, spacing } from '@/design/tokens';
15	import { textStyles } from '@/design/typography';
16	import { supabase } from '@/lib/supabase';
17	
18	// US-042 — Apply modal on campaign detail. Bottom sheet with an optional
19	// pitch field that calls the apply-to-listing edge function (US-041).
20	//
21	// Spec alignment (docs/design.md §4.3 + docs/tech-architecture.md §5.5):
22	// - Header copy "You're applying to" + listing title
23	// - Pitch (optional) text area with character counter (story AC: 280-char
24	//   cap; design.md mock shows 0/160 — story AC value used; see Spec gap
25	//   in progress.txt for US-042)
26	// - "By applying you confirm you'll follow the campaign rules." disclaimer
27	// - "Send application" CTA
28	//
29	// Edge-function field is `cover_note` per spec §5.5 / `applications.cover_note`
30	// column (the story AC says "pitch" but cover_note is canonical — same
31	// resolution as US-041's edge function).
32	//
33	// Response handling: 200 → onApplied; structured errors decoded via the
34	// FunctionsHttpError context Response (Codebase Pattern #98). For
35	// INELIGIBLE 403 the toast surfaces a one-line summary derived from the
36	// first failed condition; spec-defined 409 codes (LISTING_NOT_ACTIVE,
37	// LISTING_VERSION_CHANGED, ALREADY_APPLIED) and 404 each get their own
38	// toast. The parent reloads the listing for any state-changing error so
39	// the eligibility rail and CTA reflect the new server reality.
40	
41	const COVER_NOTE_MAX_LEN = 280;
42	
43	type SocialPlatform = 'tiktok' | 'instagram';
44	
45	type FailedCondition = {
46	  metric: string;
47	  platform: SocialPlatform | null;
48	  required: number | boolean;
49	  actual: number | boolean | null;
50	};
51	
52	type ApplySuccess = {
53	  application_id: string;
54	  listing_version_id: string;
55	};
56	
57	type ServerErrorBody = {
58	  error?: string;
59	  failed_conditions?: FailedCondition[];
60	  current_version_id?: string;
61	};
62	
63	export type ApplyFailure =
64	  | { kind: 'ineligible' }
65	  | { kind: 'version_changed' }
66	  | { kind: 'already_applied' }
67	  | { kind: 'not_active' }
68	  | { kind: 'not_found' };
69	
70	export type ApplySheetProps = {
71	  visible: boolean;
72	  listingId: string;
73	  listingTitle: string;
74	  onDismiss: () => void;
75	  onApplied: () => void;
76	  onServerStateChanged: (failure: ApplyFailure) => void;
77	};
78	
79	export function ApplySheet({
80	  visible,
81	  listingId,
82	  listingTitle,
83	  onDismiss,
84	  onApplied,
85	  onServerStateChanged,
86	}: ApplySheetProps) {
87	  const { show: showToast } = useToast();
88	  const [pitch, setPitch] = useState('');
89	  const [submitting, setSubmitting] = useState(false);
90	  const [keyboardHeight, setKeyboardHeight] = useState(0);
91	  // Synchronous submit lock (Pattern #106 — useState reads in the callback can
92	  // be stale across rapid double-taps; a ref is set before any await).
93	  const submittingRef = useRef(false);
94	
95	  // Reset the pitch + submitting flags whenever the sheet re-opens, so a prior
96	  // half-typed message doesn't leak into a fresh attempt.
97	  useEffect(() => {
98	    if (visible) {
99	      setPitch('');
100	      setSubmitting(false);
101	      submittingRef.current = false;
102	    }
103	  }, [visible]);
104	
105	  // KeyboardAvoidingView doesn't reliably push content up when nested inside a
106	  // RN <Modal> (the modal opens its own window so KAV's measured frame and the
107	  // keyboard's reported frame disagree). Listen to keyboard events directly
108	  // and apply the height as bottom padding so the CTA stays above the keyboard.
109	  useEffect(() => {
110	    const showEvt = Platform.OS === 'ios' ? 'keyboardWillShow' : 'keyboardDidShow';
111	    const hideEvt = Platform.OS === 'ios' ? 'keyboardWillHide' : 'keyboardDidHide';
112	    const showSub = Keyboard.addListener(showEvt, (e) => {
113	      setKeyboardHeight(e.endCoordinates.height);
114	    });
115	    const hideSub = Keyboard.addListener(hideEvt, () => setKeyboardHeight(0));
116	    return () => {
117	      showSub.remove();
118	      hideSub.remove();
119	    };
120	  }, []);
121	
122	  const onSubmit = useCallback(async () => {
123	    if (submittingRef.current) return;
124	    submittingRef.current = true;
125	    setSubmitting(true);
126	    const trimmed = pitch.trim();
127	    try {
128	      const { data, error } = await supabase.functions.invoke<ApplySuccess>(
129	        'apply-to-listing',
130	        {
131	          body: {
132	            listing_id: listingId,
133	            ...(trimmed.length > 0 ? { cover_note: trimmed } : {}),
134	          },
135	        },
136	      );
137	
138	      if (error) {
139	        const body = await readErrorBody(error);
140	        const failure = mapErrorBodyToFailure(body);
141	        if (failure) {
142	          showToast({
143	            message: toastForFailure(failure, body),
144	            variant: 'error',
145	          });
146	          onServerStateChanged(failure);
147	          return;
148	        }
149	        showToast({
150	          message: 'Could not send application. Try again.',
151	          variant: 'error',
152	        });
153	        return;
154	      }
155	
156	      if (!data?.application_id) {
157	        showToast({
158	          message: 'Could not send application. Try again.',
159	          variant: 'error',
160	        });
161	        return;
162	      }
163	
164	      onApplied();
165	    } catch (err) {
166	      console.error('apply-to-listing threw', err);
167	      showToast({
168	        message: 'Could not send application. Try again.',
169	        variant: 'error',
170	      });
171	    } finally {
172	      submittingRef.current = false;
173	      setSubmitting(false);
174	    }
175	  }, [pitch, listingId, showToast, onApplied, onServerStateChanged]);
176	
177	  return (
178	    <BottomSheet
179	      visible={visible}
180	      onDismiss={onDismiss}
181	      snapPoints={[0.85]}
182	      accessibilityLabel="Apply to campaign"
183	      testID="apply-sheet"
184	    >
185	      <View style={[styles.flex, { paddingBottom: keyboardHeight }]}>
186	        <View style={styles.header}>
187	          <Text style={[textStyles.caption, { color: colors.ink70 }]}>
188	            You&apos;re applying to
189	          </Text>
190	          <Text
191	            style={[textStyles.h1, { color: colors.ink }]}
192	            numberOfLines={2}
193	            testID="apply-sheet-title"
194	          >
195	            {listingTitle}
196	          </Text>
197	        </View>
198	
199	        <View style={styles.fieldGroup}>
200	          <View style={styles.labelRow}>
201	            <Text style={[textStyles.caption, { color: colors.ink70 }]}>
202	              Pitch (optional)
203	            </Text>
204	            <Text
205	              style={[textStyles.caption, { color: colors.ink40 }]}
206	              testID="apply-sheet-counter"
207	            >
208	              {pitch.length}/{COVER_NOTE_MAX_LEN}
209	            </Text>
210	          </View>
211	          <View style={[styles.inputWrap, shadows.hard]}>
212	            <TextInput
213	              value={pitch}
214	              onChangeText={setPitch}
215	              placeholder="Why are you a fit?"
216	              placeholderTextColor={colors.ink40}
217	              multiline
218	              maxLength={COVER_NOTE_MAX_LEN}
219	              style={[textStyles.body, styles.input]}
220	              accessibilityLabel="Pitch"
221	              testID="apply-sheet-pitch"
222	            />
223	          </View>
224	        </View>
225	
226	        <TouchableWithoutFeedback onPress={Keyboard.dismiss} accessible={false}>
227	          <Text style={[textStyles.caption, styles.disclaimer]}>
228	            By applying you confirm you&apos;ll follow the campaign rules.
229	          </Text>
230	        </TouchableWithoutFeedback>
231	
232	        <View style={styles.cta}>
233	          <ButtonPrimary
234	            label="Send application"
235	            onPress={onSubmit}
236	            loading={submitting}
237	            disabled={submitting}
238	            testID="apply-sheet-submit"
239	          />
240	        </View>
241	      </View>
242	    </BottomSheet>
243	  );
244	}
245	
246	async function readErrorBody(
247	  error: unknown,
248	): Promise<ServerErrorBody | null> {
249	  const ctx = (error as { context?: unknown }).context;
250	  if (
251	    !ctx ||
252	    typeof ctx !== 'object' ||
253	    !('status' in ctx) ||
254	    typeof (ctx as { json?: unknown }).json !== 'function'
255	  ) {
256	    return null;
257	  }
258	  try {
259	    return (await (ctx as Response).json()) as ServerErrorBody;
260	  } catch {
261	    return null;
262	  }
263	}
264	
265	function mapErrorBodyToFailure(
266	  body: ServerErrorBody | null,
267	): ApplyFailure | null {
268	  if (!body?.error) return null;
269	  switch (body.error) {
270	    case 'INELIGIBLE':
271	      return { kind: 'ineligible' };
272	    case 'LISTING_VERSION_CHANGED':
273	      return { kind: 'version_changed' };
274	    case 'ALREADY_APPLIED':
275	      return { kind: 'already_applied' };
276	    case 'LISTING_NOT_ACTIVE':
277	      return { kind: 'not_active' };
278	    case 'LISTING_NOT_FOUND':
279	      return { kind: 'not_found' };
280	    default:
281	      return null;
282	  }
283	}
284	
285	function toastForFailure(
286	  failure: ApplyFailure,
287	  body: ServerErrorBody | null,
288	): string {
289	  switch (failure.kind) {
290	    case 'ineligible': {
291	      const first = body?.failed_conditions?.[0];
292	      return first
293	        ? `You no longer meet ${conditionLabel(first)}.`
294	        : 'You no longer meet this campaign\u2019s requirements.';
295	    }
296	    case 'version_changed':
297	      return 'This campaign was updated. Refreshing the details.';
298	    case 'already_applied':
299	      return 'You\u2019ve already applied to this campaign.';
300	    case 'not_active':
301	      return 'This campaign is no longer accepting applications.';
302	    case 'not_found':
303	      return 'This campaign is no longer available.';
304	  }
305	}
306	
307	function conditionLabel(f: FailedCondition): string {
308	  const platform = f.platform ? platformLabel(f.platform) : '';
309	  const base = metricLabel(f.metric);
310	  return platform ? `${platform} ${base}` : base;
311	}
312	
313	function platformLabel(p: SocialPlatform): string {
314	  return p === 'tiktok' ? 'TikTok' : 'Instagram';
315	}
316	
317	function metricLabel(metric: string): string {
318	  switch (metric) {
319	    case 'min_followers':
320	      return 'minimum followers';
321	    case 'min_avg_views_last_n':
322	      return 'avg views (last 10)';
323	    case 'min_total_likes':
324	      return 'total likes';
325	    case 'min_videos_posted':
326	      return 'videos posted';
327	    case 'verified_only':
328	      return 'verified account';
329	    default:
330	      return metric;
331	  }
332	}
333	
334	const styles = StyleSheet.create({
335	  flex: { flex: 1 },
336	  header: {
337	    gap: spacing.xs,
338	    marginBottom: spacing.lg,
339	  },
340	  fieldGroup: {
341	    gap: spacing.sm,
342	  },
343	  labelRow: {
344	    flexDirection: 'row',
345	    justifyContent: 'space-between',
346	    alignItems: 'baseline',
347	  },
348	  inputWrap: {
349	    backgroundColor: colors.surface,
350	    borderRadius: radii.input,
351	    borderWidth: 2,
352	    borderColor: colors.ink,
353	  },
354	  input: {
355	    minHeight: 110,
356	    paddingHorizontal: spacing.base,
357	    paddingVertical: spacing.md,
358	    color: colors.ink,
359	    textAlignVertical: 'top',
360	  },
361	  disclaimer: {
362	    color: colors.ink70,
363	    marginTop: spacing.lg,
364	  },
365	  cta: {
366	    marginTop: 'auto',
367	    paddingTop: spacing.lg,
368	  },
369	});
